  ('7c5b5e33-5b5d-40eb-91a3-9d84894e9328', '2025-09-15T17:13:17.225664+00:00', '2025-12-17T06:47:37.847465+00:00', 'FurrMarket 4', 'furmarket-4', 'Маркет на фурри-тематику в Москве', 'Здесь можно найти любимых авторов, крафтеров, пушистиков и много красивого, яркого мерча. Мероприятие, от которого можно пищать от восторга!', '2025-08-02T00:00:00+00:00', '2024-10-01T00:00:00+00:00', 'Амбер плаза', 'Москва', 'Россия', 'market', 'completed', '{"status":"attended","roles":[]}', 250, 300, 4, 'FurrMarket растёт и развивается! Заметно больше мастеров чем в прошлые разы, появились новые категории товаров. Особенно порадовало появление фурсьют-мастеров. Организация стала лучше, есть зоны отдыха.', 'Мероприятие явно набирает обороты. Качество растёт, количество участников увеличивается. Рад видеть как развивается питерская фурри-сцена!', TRUE, TRUE, FALSE, TRUE, 600.0, 5200.0, 'Потратил чуть больше обычного, но нашёл несколько уникальных вещей которых раньше не было.', 'FurrMarket 4 | Мероприятия Fox Taffy', 'Отчёт Fox Taffy с четвёртого FurrMarket в Санкт-Петербурге', 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/gallery/events/banners/1763841499608_ocgeforsqcg.jpg', 'https://foxtaffy.fun/events/FurrMarket4', 'https://vk.com/furrmarket', FALSE, 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/gallery/events/furmarket.jpg', NULL, NULL, '[]'::jsonb, 4, 4, 4, 2, 4, 5, TRUE, '["Хорошо работающие кондиционеры", "Дружелюбная атмосфера и отзывчивые организаторы", "Интересные мастер-классы и активности", "Качественный маркет с разнообразными товарами", "Отличное озвучивание и музыкальное сопровождение"]'::jsonb, '["Тесное помещение с большим количеством людей", "Мало сидячих мест для отдыха", "Сьютерная - пустое со столом по центру помещение", "Перенос регистрации", "Некоторые задержки в расписании"]'::jsonb, 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/gallery/events/FurrMarket4/', NULL, '[]'::jsonb, NULL),
  ('87f5b09a-1fd3-47f4-a4bf-9013a2997db3', '2025-09-15T17:06:18.350267+00:00', '2025-12-09T14:36:55.65122+00:00', 'SkyFurrBurg', 'sky-furr-burg-2024', 'Афинские Игры 2025', 'Пышные сады Эллады ждут вас на приватном ретрите-конвенте в античном сеттинге от SkyFurr и Furrburg. Тут были SPA, бассейны, безлимитный бар и яркие фурри-ивенты!', '2025-07-05T00:00:00+00:00', '2024-06-15T00:00:00+00:00', 'Вилла "Аксиньино"', 'Московская область', 'Россия', 'convention', 'completed', '{"status":"attended","roles":[]}', 280, 300, 5, 'С первого взгляда место производит отличное впечатление: природа, тишина, ухоженность. Но уже в первый день стали заметны организационные проблемы: неработающие зоны, неразделённые раздевалки, технические неисправности. Несмотря на это, благодаря атмосфере, классной программе, фурсьютерам и людям — я провёл время незабываемо. Надеюсь, в будущем команда учтёт все ошибки. Я бы с радостью вернулся на обновлённую и доработанную версию этого мероприятия!', 'В целом SkyFurrBurg 2024 стал одним из самых тёплых и душевных конвентов, которые я посещал. Небольшой размер мероприятия только добавил ему уютности и семейной атмосферы. Обязательно приеду в следующем году!', TRUE, TRUE, TRUE, TRUE, 2500.0, 0.0, 'Все покупки оказались очень качественными. Питерские мастера действительно умеют делать красивые и долговечные вещи. Особенно доволен арт-коммишеном с небесной тематикой.', 'SkyFurrBurg | Мероприятия Fox Taffy', 'Отчёт Fox Taffy с конвента SkyFurrBurg в Санкт-Петербурге - самый уютный фурри-конвент с небесной тематикой', 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/Convent/events/banners/1765288236854_vwpq3n9czg.jpg', 'https://foxtaffy.fun/events/SkyFurrBurg', 'http://skyfurrburg.ru', FALSE, 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/Convent/events/avatars/1765288221251_tuo8swtdaln.png', NULL, NULL, '[]'::jsonb, 4, 2, 5, 5, 3, 4, TRUE, '["Интересная и разнообразная программа.", "Два фурсьютера — большая помощь для гостей", "Приятный бар с отзывчивыми барменами.", "Уютная территория с прудом и зеленью.", "Надувные матрасы для отдыха и общения.", "Фурсьютеры создавали отличное настроение."]'::jsonb, '["Мешал храп из соседней палатки.", "Неудобный сайт с устаревшей информацией.", "Неприятный запах из туалета в гримёрке.", "Общая раздевалка у бассейна.", "Хамам и джакузи не работали, бассейн холодный.", "Некоторые помещения были закрыты.", "Проблемы с электричеством и задержки в расписании."]'::jsonb, 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/gallery/events/SFB/', NULL, '[]'::jsonb, '2025-07-08'),
  ('3d49b41e-c624-43c6-8f20-95c431182ae4', '2025-09-24T16:16:46.023+00:00', '2025-12-13T13:04:43.369646+00:00', 'AnyFurry Fest VI', 'any-furry-fest-6', 'Крупнейший фурри-фестиваль России', 'Фурри-фестиваль для всех пушистых с насыщенной программой: маркет художников, конкурс фурсьютов, фотозона, настольные и ролевые игры, VR, кинопоказы, мастер-классы, лекции и сценические активности.', '2025-11-29T00:00:00+00:00', '2024-06-01T00:00:00+00:00', 'Веткина улица', 'Москва', 'Россия', 'festival', 'completed', '{"status":"attended","roles":["vip"]}', 150, 100, 5, 'Конвент получился невероятно атмосферным и тёплым — сочетание фростпанк-стилистики, живописной природы и заботливо подготовленного лагеря превратило суровые условия в комфортное приключение. Участники отмечали вкусную и сытную кухню, уют у костра, интересные квесты, неожиданные повороты сюжета и море подарков. Даже скептики, которые не любят палаточные мероприятия, были приятно удивлены уровнем организации, дружелюбной атмосферой и чувством единства. Мероприятие запомнилось не только тематикой, но и искренними эмоциями, новыми знакомствами и тем, что здесь каждый смог найти себе место — будь то участие в конкурсах, барные посиделки, вечерние разговоры или просто наблюдение за событиями. Турфур оставил ощущение, что это не просто конвент, а большое тёплое семейное приключение, в которое хочется вернуться. ❤️', 'TourFurr показал что фурри-мероприятия могут быть очень разнообразными. Иногда простое общение на природе ценнее любых конвентов.', TRUE, TRUE, TRUE, TRUE, 300.0, 900.0, 'Трат практически не было, кроме взноса на общий стол. Главная ценность мероприятия - в общении.', 'TourFurr | Мероприятия Fox Taffy', 'Отчёт Fox Taffy с фурри-пикника TourFurr в Сокольниках', 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/Convent/events/banners/1765593496165_qc0rtg73nu.jpg', 'https://foxtaffy.fun/events/aff6', 'https://vk.com/anyfurryfest', FALSE, 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/gallery/events/aff5.jpg', NULL, NULL, '[{"name": "Чай Орса", "image": "https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/gallery/events/anyfurry-fest-vi/buy.jpg", "price": "400"}, {"name": "Морковка", "image": "https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/gallery/events/anyfurry-fest-vi/Buy2.jpg", "price": "500"}]'::jsonb, 5, 5, 5, 4, 5, NULL, TRUE, '["Большое помещение", "Свежо в сьюте", "Много людей - но не мешались"]'::jsonb, '["Место с охраной иногда раздражала", "Сьютерная маленькая, можно было расширить"]'::jsonb, 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/gallery/events/anyfurry-fest-vi/', NULL, '[]'::jsonb, NULL),
  ('0d47bae2-592a-45b5-ad1b-c3e5e4719ff6', '2026-01-26T16:18:52.504+00:00', '2026-01-26T16:18:52.504+00:00', 'Eurofurence', 'eurofurence-1769444332504', NULL, 'Это ежегодная международная выставка меха, которая проходит в Германии, в Гамбурге.', '2026-08-19T00:00:00+00:00', NULL, 'CCH', 'Гамбург', 'Германия', 'convention', 'completed', '{"status":"planning","roles":[]}', 0, 5000, NULL, '', NULL, TRUE, TRUE, TRUE, FALSE, 0.0, 0.0, '', 'Eurofurence', NULL, NULL, NULL, 'https://www.eurofurence.org/EF30/', FALSE, 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/Convent/events/avatars/1769443833141_fz09u0fs6f.jpg', NULL, NULL, '[]'::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, '[]'::jsonb, '[]'::jsonb, 'eurofurence', NULL, '[]'::jsonb, '2026-08-23'),
  ('3e243bed-cc5b-49ff-9115-45bc09b21cad', '2025-09-15T17:13:17.225664+00:00', '2025-12-09T14:03:28.134515+00:00', 'Fox Family Fest', 'fff', 'Выстовка-фестиваль домашних лис', 'Ежегодная образовательная выставка-фестиваль домашних лис. Вас ждут лекции о правильном отношении к дикой природе, о сложностях содержания экзотических животных в домашних условиях, о нюансах ветеринарного сопровождения и кормления, а также мастер-классы, тематическая ярмарка и фотозона с экзотическими питомцами', '2025-05-31T00:00:00+00:00', '2024-05-10T00:00:00+00:00', 'ТРЦ', 'Москва', 'Россия', 'festival', 'completed', '{"status":"attended","roles":[]}', 180, 200, 5, 'Невероятный летний фест! Сочетание природы и фурри-культуры оказалось идеальным. Программа была разнообразной - от мастер-классов в помещении до игр на свежем воздухе. Вечерние мероприятия у костра особенно запомнились.', 'FFF показал что фурри-мероприятия летом могут быть ещё лучше! Свежий воздух, природа, друзья - что ещё нужно для счастья?', TRUE, TRUE, TRUE, TRUE, 2200.0, 6800.0, 'Потратился больше обычного на уникальные летние товары - солнцезащитные очки с ушками, летние значки, и конечно же традиционные покупки.', 'FFF | Мероприятия Fox Taffy', 'Отчёт Fox Taffy с летнего фурри-феста FFF в Подмосковье', 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/Convent/events/banners/1765289004699_6rdud83jhno.jpg', 'https://foxtaffy.fun/events/fff', 'https://foxfamilyfest.ru/', FALSE, 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/gallery/events/fff.jpg', NULL, NULL, '[]'::jsonb, 5, 5, 5, 5, 3, NULL, TRUE, '["Большая локация", "Много маркетов", "Еноты лисы и хорьки", "Контактные животные"]'::jsonb, '["Далеко от метро", "Скучно после 2х часов"]'::jsonb, 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/gallery/events/fox-family-fest/', NULL, '[]'::jsonb, NULL),
