  ('b47658ea-6d94-44c1-bb49-b95d98d71c59', '2026-02-01T23:35:48.24+00:00', '2026-02-01T23:35:48.24+00:00', 'Foxwood: Circus', 'foxwood-circus', NULL, 'Цирковая тематика', '2026-05-14T00:00:00+00:00', NULL, 'Парк-отель Розендорф', 'Московская область', 'Россия', 'convention', 'completed', '{"status":"registered","roles":[]}', NULL, 200, NULL, '', NULL, TRUE, TRUE, TRUE, FALSE, 0.0, 0.0, '', 'Foxwood: Circus', NULL, NULL, NULL, 'https://foxwood.camp', FALSE, 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/Convent/events/avatars/1769988846237_1q94b13kpg0h.jpg', NULL, NULL, '[]'::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, '[]'::jsonb, '[]'::jsonb, '', NULL, '[]'::jsonb, '2026-05-17'),
  ('34592274-88e2-447e-b01a-f2468b8774d8', '2025-09-15T17:13:17.225664+00:00', '2025-12-09T14:07:29.695471+00:00', 'FoxWood: Back to 2000s', 'foxwood-2000s', 'Эпоха ярких красок, зажигательных хитов и незабываемой атмосферы 2000-х!', 'FoxWood — это ежегодный фурри-конвент с душой. Место, где собираются друзья, сообщество и вдохновение. Здесь царит уютная, теплая атмосфера, в которой каждый чувствует себя своим — будь ты в фурсьюте, с блокнотом художника или просто с открытым сердцем. В 2025 году мы перенеслись в яркие и свободные 2000-е — эпоху, когда музыка звучала с кассетников, пиксели грели душу, а дружба рождалась в оффлайне. Мы воссоздали стиль того времени через конкурсы, фотозоны, танцы, фандомные активности и море живого общения.', '2025-05-15T00:00:00+00:00', '2024-06-20T00:00:00+00:00', 'Парк-отель "Розендорф"', 'Подмосковье', 'Россия', 'convention', 'completed', '{"status":"attended","roles":["volunteer"]}', 160, 180, 5, 'Совершенно потрясающая концепция! Лесная тематика смешанная с ностальгией по нулевым создала невероятную атмосферу. Декорации были на высшем уровне - везде деревья, мох, а музыка из 2000-х добавляла особого шарма.', 'FoxWood стал одним из самых запоминающихся мероприятий года. Такой креативный подход к тематике встречается редко. Надеюсь на продолжение серии!', TRUE, TRUE, TRUE, TRUE, 2800.0, 7500.0, 'Купил много тематических вещей - лесные значки, ретро-постеры, и конечно же эксклюзивный мерч мероприятия в стиле 2000-х.', 'FoxWood 2000s | Мероприятия Fox Taffy', 'Отчёт Fox Taffy с ретро-мероприятия FoxWood: Back to 2000s', 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/Convent/events/banners/1765289204288_x0vq2cnwqz.jpg', 'https://foxtaffy.fun/events/foxwood', 'https://vk.com/foxwood', FALSE, 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/gallery/events/foxwood.jpg', NULL, NULL, '[]'::jsonb, 5, 5, 5, 5, 5, 5, TRUE, '[]'::jsonb, '[]'::jsonb, NULL, NULL, '[]'::jsonb, '2025-05-18'),
