  ('5fd24c3d-7672-4017-b7cc-0fcd2f44bb51', '2025-09-15T17:13:17.225664+00:00', '2025-12-09T14:10:20.278339+00:00', 'Any Furry Fest V', 'any-furry-fest-5', 'Крупнейший фурри-фестиваль России', 'Фурри-фестиваль для всех пушистых с насыщенной программой: маркет художников, конкурс фурсьютов, фотозона, настольные и ролевые игры, VR, кинопоказы, мастер-классы, лекции и сценические активности.', '2024-10-19T00:00:00+00:00', '2024-04-01T00:00:00+00:00', 'Новосущёвский', 'Москва', 'Россия', 'festival', 'completed', '{"status":"attended","roles":["vip"]}', 150, 200, 5, 'В целом мероприятие оставило очень приятное впечатление. Несмотря на некоторые организационные недостатки, атмосфера и контент полностью компенсировали их. Обязательно посещу это мероприятие снова в следующем году и буду рекомендовать его друзьям.', 'AFF5 превзошёл все мои ожидания. Это было одно из лучших фурри-мероприятий, которые я посещал. Качество контента, уровень организации и атмосфера - всё на 5+. Уже жду следующего года!', TRUE, TRUE, TRUE, TRUE, 3500.0, 5000.0, 'Потратил больше запланированного, но каждая покупка того стоила. Особенно доволен заказанными артами и уникальными товарами от приглашённых мастеров.', 'Any Furry Fest V | Мероприятия Fox Taffy', 'Отчёт Fox Taffy с крупнейшего фурри-фестиваля России Any Furry Fest V в Москве', 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/Convent/events/banners/1765289391830_ybw46b3bp3d.jpg', 'https://foxtaffy.fun/events/aff5', 'https://vk.com/anyfurryfest', FALSE, 'https://plugjsubjcfblzkabjia.supabase.co/storage/v1/object/public/gallery/events/aff5.jpg', NULL, NULL, '[]'::jsonb, 5, 5, 5, 3, 5, NULL, TRUE, '["Разнообразная и насыщенная программа", "Дружелюбная атмосфера и отзывчивые организаторы", "Интересные мастер-классы и активности", "Качественный маркет с разнообразными товарами", "Отличное озвучивание и музыкальное сопровождение"]'::jsonb, '["Тесное помещение с недостаточной вентиляцией", "Мало сидячих мест для отдыха", "Высокие 